mapper.select:
SELECT id, user_id, identity_type, identity_key, credential_hash, verified, meta_json, created_at, updated_at
FROM app_user_identity
WHERE identity_type = #{identityType}
  AND identity_key = #{identityKey}
LIMIT 1

SELECT id, user_id, identity_type, identity_key, credential_hash, verified, meta_json, created_at, updated_at
FROM app_user_identity
WHERE user_id = #{userId}
  AND identity_type = #{identityType}
LIMIT 1
